// deque
class Solution {
public:
    string finalString(string s) {
        deque<char> dq;
        int parity = 0;
        for (const auto& x : s) {
            if (x == 'i') {
                parity ^= 1;
            } else {
                if (parity) {
                    dq.emplace_front(x);
                } else {
                    dq.emplace_back(x);
                }
            }
        }
        if (parity) {
            reverse(begin(dq), end(dq));
        }
        return string(cbegin(dq), cend(dq));
    }
};

# Time:  O(n)
# Space: O(n)

import collections


# deque
class Solution(object):
    def finalString(self, s):
        """
        :type s: str
        :rtype: str
        """
        dq = collections.deque()
        parity = 0
        for x in s:
            if x == 'i':
                parity ^= 1
            else:
                dq.appendleft(x) if parity else dq.append(x)
        if parity:
            dq.reverse()
        return "".join(dq)
